import{_ as d,o as e,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"SKAdNetwork Data","description":"","frontmatter":{"title":"SKAdNetwork Data","slug":"skadnetwork-data"},"headers":[],"relativePath":"marketer-hub/skadnetwork-data.md","filePath":"marketer-hub/skadnetwork-data.md"}'),r={name:"marketer-hub/skadnetwork-data.md"};function i(s,t,n,c,l,h){return e(),a("div",null,[...t[0]||(t[0]=[o('<h2 id="postback-data-tiers" tabindex="-1">Postback Data Tiers <a class="header-anchor" href="#postback-data-tiers" aria-label="Permalink to &quot;Postback Data Tiers&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Tier 0</th><th>Tier 1</th><th>Tier 2</th><th>Tier 3</th></tr></thead><tbody><tr><td><strong>Postback 1</strong></td><td>- <code>source-identifier</code></td><td>- <code>source-identifier</code> - <code>coarse-conversion-value</code></td><td>- <code>source-identifier</code> - <code>conversion-value</code></td><td>- <code>source-identifier</code> - <code>conversion-value</code> - <code>source-app-id</code> or <code>source-domain</code></td></tr><tr><td><strong>Postback 2 + 3</strong></td><td>n/a</td><td>- <code>source-identifier</code> - <code>coarse-conversion-value</code></td><td>- <code>source-identifier</code> - <code>coarse-conversion-value</code></td><td>- <code>source-identifier</code> - <code>coarse-conversion-value</code></td></tr></tbody></table><h2 id="postback-measurement-windows" tabindex="-1">Postback Measurement Windows <a class="header-anchor" href="#postback-measurement-windows" aria-label="Permalink to &quot;Postback Measurement Windows&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Window Spans</th></tr></thead><tbody><tr><td>Postback 1</td><td>Days 0-2</td></tr><tr><td>Postback 2</td><td>Days 3-7</td></tr><tr><td>Postback 3</td><td>Days 8-35</td></tr></tbody></table><h2 id="fields" tabindex="-1">Fields <a class="header-anchor" href="#fields" aria-label="Permalink to &quot;Fields&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Returned by Apple Postback</p><p>General and Last Attributed Touch Data fields <strong>do not</strong> come from the Apple Postback for SKAdNetwork.</p></div><h3 id="general-fields" tabindex="-1">General Fields <a class="header-anchor" href="#general-fields" aria-label="Permalink to &quot;General Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th><th>Example</th><th>Availability</th></tr></thead><tbody><tr><td><code>id</code></td><td>varchar</td><td>SKadNetwork Message ID, unique ID created by Branch for every postback received.</td><td>e92eb789-2e93-4ada-91d4-b758a900cb2e</td><td>SKAN 3+</td></tr><tr><td><code>timestamp</code></td><td>bigint</td><td>Timestamp representing when Branch received the postback from the ad network.</td><td>1620415056299</td><td>SKAN 3+</td></tr><tr><td><code>invalid_reason</code></td><td>varchar</td><td>Reason Branch marks postback from ad network invalid. Only available for skadnetwork-invalid-messages.</td><td>INVALID_SIGNATURE</td><td>SKAN 3+</td></tr><tr><td><code>app_id</code></td><td>bigint</td><td>Branch App ID.</td><td>638469555697504342</td><td>SKAN 3+</td></tr><tr><td><code>organization_id</code></td><td>bigint</td><td>Branch Organization ID.</td><td>862418696042206147</td><td>SKAN 3+</td></tr><tr><td><code>annotation_dollar_3p</code></td><td>varchar</td><td>Branch 3p value of the ad network that sent the postback.</td><td>a_tiktok_ads</td><td>SKAN 3+</td></tr><tr><td><code>annotation_conversion_value_mapped_value</code></td><td>varchar</td><td>Mapped value of the conversion value received (as set in the Branch Dashboard).</td><td>COMPLETE_REGISTRATION</td><td>SKAN 3+</td></tr><tr><td><code>annotation_customer_event_alias</code></td><td>varchar</td><td>Mapped value of the customer event alias</td><td>Purchase1</td><td>SKAN 3+</td></tr><tr><td><code>annotation_revenue_lower</code></td><td>varchar</td><td>Mapped value of the lower revenue value received.</td><td>5.0</td><td>SKAN 3+</td></tr><tr><td><code>annotation_revenue_upper</code></td><td>varchar</td><td>Mapped value of the upper revenue value received.</td><td>20.0</td><td>SKAN 3+</td></tr></tbody></table><h3 id="last-attributed-touch-data-fields" tabindex="-1">Last Attributed Touch Data Fields <a class="header-anchor" href="#last-attributed-touch-data-fields" aria-label="Permalink to &quot;Last Attributed Touch Data Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th><th>Example</th><th>Availability</th></tr></thead><tbody><tr><td><code>last_attributed_touch_data_tilde_ad_set_id</code></td><td>varchar</td><td>Ad set ID - Optional field supplied by some ad partners.</td><td>bd7ffd1c-53de-498d-981c-57912fc6de91</td><td>SKAN 3+</td></tr><tr><td><code>last_attributed_touch_data_tilde_campaign_id</code></td><td>varchar</td><td>Campaign ID (non-Apple ID) - Optional field supplied by some ad partners.</td><td>64d02bc0-f4d4-41ff-a93e-1e20f8d7f345</td><td>SKAN 3+</td></tr><tr><td><code>last_attributed_touch_data_tilde_campaign</code></td><td>varchar</td><td>Campaign Name - Optional field supplied by some ad partners.</td><td>IOS14_Campaign_Male(18-30)_Fantou</td><td>SKAN 3+</td></tr></tbody></table><h3 id="body-fields" tabindex="-1">Body Fields <a class="header-anchor" href="#body-fields" aria-label="Permalink to &quot;Body Fields&quot;">​</a></h3><p>All of the body fields come from the Apple Postback for SKAdNetwork except for the following field(s):</p><ul><li><code>body_source_domain</code></li></ul><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th><th>Example</th><th>Availability</th></tr></thead><tbody><tr><td><code>body_transaction_id</code></td><td>varchar</td><td>A unique value for this validation; use for deduplicating install [and probably conversion] validation messages. This is part of the postback from Apple.</td><td>38b64295-0875-4d2e-868a-3969e2fc8e1e</td><td>SKAN 3+</td></tr><tr><td><code>body_version</code></td><td>varchar</td><td>The version of the SKAdNetwork API being used by the publisher app.</td><td>2.0</td><td>SKAN 2+</td></tr><tr><td><code>body_ad_network_id</code></td><td>varchar</td><td>ID of the attributed ad network on the postback. This ID is assigned by Apple when an ad network registers for SKAdNetwork.</td><td>424m5lk.skadnetwork</td><td>SKAN 3+</td></tr><tr><td><code>body_campaign_id</code></td><td>integer</td><td>Campaign ID which will be a number from 1-100.</td><td>47</td><td>SKAN 3+</td></tr><tr><td><code>body_app_id</code></td><td>bigint</td><td>The advertiser app ID - App Store ID.</td><td>1350133141</td><td>SKAN 3+</td></tr><tr><td><code>body_attribution_signature</code></td><td>varchar</td><td>Apple’s attribution signature in install/conversion Postbacks, that is used to verify the validity of the postback.</td><td>MDUCGec/xnWx==</td><td>SKAN 3+</td></tr><tr><td><code>body_redownload</code></td><td>boolean</td><td>If false, the postback represents an install If true, the postack represents a reinstall.</td><td>false</td><td>SKAN 3+</td></tr><tr><td><code>body_source_app_id</code></td><td>bigint</td><td>The publisher app ID - App Store ID. This may be not included by Apple if number of postbacks do not reach a certain threshold.</td><td>447188370</td><td>SKAN 3+</td></tr><tr><td><code>body_conversion_value</code></td><td>integer</td><td>Conversion value (0-63) on the postback, which represents a post-install action. The highest conversion value that the end user performed in during the timer will be reflected. This may be not included by Apple if number of postbacks do not reach a certain threshold.</td><td>15</td><td>SKAN 3+</td></tr><tr><td><code>body_fidelity_type</code></td><td>integer</td><td>If 1, this represents a Store-Kit rendered ad (App Store product page, rendered by Store Kit) If 0, this represents a &quot;View-Through&quot; ad (Custom, provided by ad network).</td><td>1</td><td>SKAN 3+</td></tr><tr><td><code>body_did_win</code></td><td>boolean</td><td>If it is true, that will signify that the partner won the claim.</td><td>true</td><td>SKAN 3+</td></tr><tr><td><code>body_postback_sequence_index</code></td><td>integer</td><td>Enables marketers to easily distinguish between postbacks 1, 2, and 3. The possible integer values of 0, 1, and 2 signify the order of postbacks that result from the three conversion windows. For more information, see <a href="https://developer.apple.com/documentation/storekit/skadnetwork/receiving_postbacks_in_multiple_conversion_windows" target="_blank" rel="noreferrer">Receiving postbacks in multiple conversion windows</a>.</td><td>1</td><td>SKAN 4+</td></tr><tr><td><code>body_source_identifier</code></td><td>string</td><td>The hierarchical source identifier, with 2 or 4 digits (depending on the postback value).</td><td>12</td><td>SKAN 3+</td></tr><tr><td><code>body_coarse_conversion_value</code></td><td>string</td><td>A coarse value, if the app provides one.</td><td>low</td><td>SKAN 4+</td></tr><tr><td><code>body_source_domain</code></td><td>For attributable web ads.</td><td>Ad set name - Optional field supplied by some ad partners. <strong>Does not</strong> come from the Apple Postback.</td><td>IOS14-Install-Male(18+)</td><td>SKAN 3+</td></tr></tbody></table>',14)])])}const u=d(r,[["render",i]]);export{b as __pageData,u as default};
